    public static string Format(string messageId, string camelPropertyName)
    {
        var lookup = messageId + ":" + camelPropertyName;
        if (!FieldIds.TryGetValue(lookup, out var id))
        {
            throw new InvalidOperationException($"No field id for {lookup}");
        }
        return messageId + "_" + id.ToString("D3");
    }

    public static string Alias(string aliasName) => Format("997", aliasName);

